UPDATE ai_agent_state_log
SET state_size_bytes = #{stateSizeBytes},
context_message_count = #{contextMessageCount},
summary_exists = #{summaryExists},
summary_preview = #{summaryPreview},
last_saved_at = #{lastSavedAt}

    , last_compacted_at = #{lastCompactedAt}

WHERE runtime_user_key = #{runtimeUserKey}
AND runtime_session_key = #{runtimeSessionKey}
AND tenant_id = #{tenantId}
